const p = $input.first().json.body || $input.first().json;
const nombre = p.nombre || "Interesado";
const telefono = p.telefono || "";
const propiedad = p.propiedad || "";
const presupuesto = p.presupuesto || "";
const mensaje = p.mensaje || "";

const system_prompt = "Eres el asistente de una inmobiliaria. Calificas leads interesados en propiedades por WhatsApp o formulario web.

Lead recibido:
- nombre: " + nombre + "
- telefono: " + telefono + "
- propiedad de interes: " + propiedad + "
- presupuesto declarado: " + presupuesto + "
- mensaje: " + mensaje + "

Reglas de calificacion:
- LISTO_PARA_VISITA: menciona presupuesto o financiamiento concreto y pide ver la propiedad pronto.
- EXPLORANDO: muestra interes real pero sin presupuesto definido ni urgencia por visitar.
- NO_CALIFICA: presupuesto claramente insuficiente, busca otra zona/tipo, o mensaje generico sin intencion real.

Responde UNICAMENTE con un JSON valido, sin texto extra:
- categoria: LISTO_PARA_VISITA, EXPLORANDO o NO_CALIFICA
- puntuacion: numero de 0 a 100
- razon: explicacion breve (1 frase)
- respuesta_sugerida: mensaje corto, calido y profesional en espanol. Si es LISTO_PARA_VISITA, confirma que se le agendara una visita pronto. Maximo 3 frases.";

return [{ json: Object.assign({}, p, { system_prompt: system_prompt }) }];

const original = $("Armar Prompt de Calificacion Inmobiliaria").first().json;
const resp = $input.first().json;
const textoBruto = resp.message.content;
const limpio = textoBruto.trim().replace(/^```json\s*/i, "").replace(/```\s*$/, "");
const contenido = JSON.parse(limpio);
return [{ json: Object.assign({}, contenido, { nombre: original.nombre, telefono: original.telefono, propiedad: original.propiedad }) }];
